		current := time.Date(now.Year(), now.Month(), 1, 0, 0, 0, 0, time.UTC)
		previous := current.AddDate(0, -1, 0)
		return month.Equal(current) || month.Equal(previous)
	}
	if q.StartedAfter != nil && !next.After(*q.StartedAfter) {
		return false
